#include "surface_ops.h"
__declspec(dllexport) void run(void) { CvmState*s=cvm_state(); H w_h,h_h,o; cvm_pop(h_h); cvm_pop(w_h); cvm_zero(o); surface_class(); if(s){int w=(int)cvm_h_to_u64(w_h),h=(int)cvm_h_to_u64(h_h); if(w<1)w=800; if(h<1)h=600; if(!s->surface_hwnd)s->surface_hwnd=CreateWindowA("CVM_Surface","CVM",WS_OVERLAPPEDWINDOW|WS_VISIBLE,CW_USEDEFAULT,CW_USEDEFAULT,w,h,0,0,GetModuleHandleA(0),0); ShowWindow(s->surface_hwnd,SW_SHOW); UpdateWindow(s->surface_hwnd); s->surface_w=w; s->surface_h=h; o[0]=s->surface_hwnd?1:0;} cvm_push(o); cnext(); }
